import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String inputString = scanner.nextLine();

        int maxLength = Math.min(inputString.length(), 10); // Limit to buffer size

        char[] buffer = new char[10];

        // Copy only up to maxLength characters into the buffer
        inputString.getChars(0, maxLength, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
